import{_ as e,o as a,c as i,a2 as n}from"./chunks/framework.D5wUhsuj.js";const u=JSON.parse('{"title":"Server & Gateway Errors","description":"","frontmatter":{},"headers":[],"relativePath":"troubleshooting/server-errors.md","filePath":"troubleshooting/server-errors.md"}'),t={name:"troubleshooting/server-errors.md"};function l(r,s,p,o,h,d){return a(),i("div",null,[...s[0]||(s[0]=[n(`<h1 id="server-gateway-errors" tabindex="-1">Server &amp; Gateway Errors <a class="header-anchor" href="#server-gateway-errors" aria-label="Permalink to &quot;Server &amp; Gateway Errors&quot;">​</a></h1><p>The 5xx family — these mean Nginx received the request fine, but something behind it (PHP-FPM, usually) didn&#39;t respond the way Nginx expected.</p><h2 id="_502-bad-gateway" tabindex="-1">502 Bad Gateway <a class="header-anchor" href="#_502-bad-gateway" aria-label="Permalink to &quot;502 Bad Gateway&quot;">​</a></h2><p><span class="ap-pill ap-pill-common">Common</span> The single most common error you&#39;ll see running a PHP site. It means Nginx tried to hand the request to PHP-FPM and either got no response or an invalid one.</p><p><strong>Check in this order:</strong></p><p><strong>1. Is PHP-FPM actually running?</strong></p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">aidipanel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> service:status</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>If the site&#39;s PHP-FPM version shows stopped or crashed:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">aidipanel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> service:restart</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> php8.4-fpm</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # match the site&#39;s actual version</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><strong>2. Does the site&#39;s error log name the actual problem?</strong></p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">aidipanel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> log:tail</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --domain</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> example.com</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --type</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> error</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>This is usually faster than guessing — look for <code>PHP Fatal error</code>, <code>child exited with code</code>, or <code>unexpected FastCGI record</code>.</p><p><strong>3. Did a plugin or script just crash the PHP-FPM pool?</strong></p><p>A plugin (WordPress) or package (Laravel) throwing a fatal error, hitting a memory limit, or segfaulting can take down that site&#39;s entire PHP-FPM pool — which then 502s <em>every</em> page on that site, not just the one that crashed, until the pool restarts.</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Restart just this site&#39;s pool</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">aidipanel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> service:restart</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> php8.4-fpm</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># If it immediately crashes again, something is fatally erroring on every request —</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># check the error log, then deactivate the most recently changed plugin/theme:</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /home/example/htdocs/example.com/wp-content/plugins</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mv</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> suspect-plugin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> suspect-plugin.disabled</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><div class="tip custom-block"><p class="custom-block-title">A malformed response looks the same as a crash</p><p>An error like <code>upstream sent unexpected FastCGI record: 3</code> in the Nginx error log means PHP-FPM sent back something Nginx couldn&#39;t parse as a valid response — not necessarily a crash. This is often caused by a plugin that outputs something before headers are sent (a stray <code>echo</code>, a BOM character at the top of a file, a warning printed to stdout instead of the log). If disabling a recently added/updated plugin resolves it, that plugin is almost certainly the cause — worth reporting upstream to the plugin author with this exact error string.</p></div><p><strong>4. Check the socket path matches.</strong></p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> fastcgi_pass</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/nginx/sites-available/example.com.conf</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ls</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -la</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /run/php/</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>The socket named in the vhost (e.g. <code>php8.4-fpm-example.sock</code>) needs to actually exist in <code>/run/php/</code>. If it doesn&#39;t, PHP-FPM for that version/site combination isn&#39;t running — see step 1.</p><h2 id="_502-right-after-switching-php-versions" tabindex="-1">502 right after switching PHP versions <a class="header-anchor" href="#_502-right-after-switching-php-versions" aria-label="Permalink to &quot;502 right after switching PHP versions&quot;">​</a></h2><p><span class="ap-pill ap-pill-common">Common</span> If this happens immediately after <code>php:version --set</code>, the vhost&#39;s socket reference and the actual running pool are momentarily out of sync — normally <code>php:version</code> handles this atomically, but if it was interrupted:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Confirm what the site is actually configured for now</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">aidipanel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> php:version</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --domain</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> example.com</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Confirm that version&#39;s FPM service is running</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">aidipanel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> service:status</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># If needed, restart it explicitly</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">aidipanel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> service:restart</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> php8.4-fpm</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>If the vhost still references the <em>old</em> version&#39;s socket path, re-run the version switch:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">aidipanel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> php:version</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --domain</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> example.com</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --set</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 8.4</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="_503-service-unavailable" tabindex="-1">503 Service Unavailable <a class="header-anchor" href="#_503-service-unavailable" aria-label="Permalink to &quot;503 Service Unavailable&quot;">​</a></h2><p><span class="ap-pill ap-pill-common">Common</span> Usually means PHP-FPM&#39;s pool is completely saturated — every worker is busy and new requests are being rejected rather than queued.</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Check current pool load</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">aidipanel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> php:info</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 8.4</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>If this happens under real traffic spikes rather than being a one-off, the PHP-FPM pool&#39;s <code>pm.max_children</code> may be too low for your server&#39;s RAM. This is a pool-level tuning setting in <code>/etc/php/&lt;version&gt;/fpm/pool.d/&lt;site-user&gt;.conf</code> — raise it cautiously and watch RAM usage, since each additional child process costs memory.</p><p>A 503 that only appears for a few seconds and then clears up on its own is often just a service restart in progress (Nginx or PHP-FPM reloading) — safe to ignore if it&#39;s brief and one-off.</p><h2 id="_500-internal-server-error-white-screen" tabindex="-1">500 Internal Server Error / white screen <a class="header-anchor" href="#_500-internal-server-error-white-screen" aria-label="Permalink to &quot;500 Internal Server Error / white screen&quot;">​</a></h2><p><span class="ap-pill ap-pill-common">Common</span> Unlike a 502 (Nginx ↔ PHP-FPM communication problem), a 500 means PHP-FPM <em>did</em> respond, but the application itself hit a fatal error. WordPress often shows this as a blank white page rather than an actual &quot;500&quot; message — same underlying cause.</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">aidipanel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> log:tail</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --domain</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> example.com</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --type</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> error</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># or, for WordPress specifically, if WP_DEBUG_LOG is enabled:</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tail</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /home/example/htdocs/example.com/wp-content/debug.log</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p><strong>Most common causes, roughly in order of likelihood:</strong></p><ol><li><strong>A plugin or theme update introduced a fatal error.</strong> Rename the plugin folder to disable it (see the 502 section above) and reload.</li><li><strong>PHP memory limit exceeded.</strong> Look for <code>Allowed memory size of ... exhausted</code> in the log.</li><li><strong>A PHP version incompatibility</strong> — code using a function or syntax removed in your current PHP version. Common after switching PHP major versions; see <a href="/docs/guide/php#setting-a-sites-php-version">PHP Management</a>.</li><li><strong>A corrupted <code>.htaccess</code>-equivalent rule</strong> in the Nginx vhost, if you hand-edited it recently — check with <code>nginx -t</code>.</li></ol><h2 id="_504-gateway-timeout" tabindex="-1">504 Gateway Timeout <a class="header-anchor" href="#_504-gateway-timeout" aria-label="Permalink to &quot;504 Gateway Timeout&quot;">​</a></h2><p><span class="ap-pill ap-pill-rare">Less common</span> A specific request is taking longer to process than PHP-FPM&#39;s configured timeout allows, so Nginx gives up waiting.</p><p>Typical causes: a large file upload, a slow external API call inside the request (payment gateway, email service), an unoptimized database query, or a bulk import/export operation.</p><ul><li>If it&#39;s a one-off heavy operation (large media import, migration script), consider running it via SSH/WP-CLI directly instead of through the browser, which isn&#39;t bound by the same request timeout.</li><li>If it&#39;s a specific recurring page, look at what that page does — this is almost always an application-level performance problem (a slow query, an external API with no timeout of its own) rather than something to fix at the server level.</li></ul><h2 id="installer-or-install-time-failures" tabindex="-1">Installer or install-time failures <a class="header-anchor" href="#installer-or-install-time-failures" aria-label="Permalink to &quot;Installer or install-time failures&quot;">​</a></h2><p>If the <em>installer itself</em> fails partway through rather than a live site, the first stop is always:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /var/log/aidipanel-install.log</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Common install-time snags:</p><ul><li><strong>Installing on a server that already runs Nginx/Apache/MySQL</strong> — port 80/443 or 3306 conflicts with existing services. A fresh VPS avoids this entirely; see <a href="/docs/guide/installation#requirements">Installation → Requirements</a>.</li><li><strong>Interrupted install</strong> (SSH disconnected mid-run) — inspect the install log before retrying. Do not run the installer over an installed panel; use <code>sudo aidipanel self:update</code> for an existing installation.</li><li><strong>Insufficient RAM/disk</strong> — installing MariaDB/MySQL + PHP + Nginx genuinely needs the <a href="/docs/guide/installation#requirements">minimum specs</a>; a 512MB box can work but leaves very little headroom for an actual WordPress site on top.</li></ul><h2 id="still-stuck" tabindex="-1">Still stuck? <a class="header-anchor" href="#still-stuck" aria-label="Permalink to &quot;Still stuck?&quot;">​</a></h2><p>If the error log doesn&#39;t point anywhere obvious, <code>nginx -t</code> is worth running any time you suspect a config problem — it validates syntax and will refuse to reload on a broken config, which usually surfaces the exact line at fault:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nginx</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -t</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div>`,46)])])}const g=e(t,[["render",l]]);export{u as __pageData,g as default};
